class Solution {
public:
    ListNode* deleteDuplicates(ListNode* head) {
        ListNode dummy(0, head), *prev = &dummy;
        while (prev->next) {
            if (prev->next->next && prev->next->val == prev->next->next->val) {
                int v = prev->next->val;
                while (prev->next && prev->next->val == v)
                    prev->next = prev->next->next;
            } else prev = prev->next;
        }
        return dummy.next;
    }
};
